import { products } from "../data.js";
import type {
  ProductFilter,
  ProductListResult,
  ProductDetail,
  ServiceResult,
} from "../types.js";

export function listProducts(filter: ProductFilter): ProductListResult {
  let filtered = [...products];

  if (filter.category) {
    filtered = filtered.filter((p) => p.category === filter.category);
  }

  if (filter.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filter.minPrice!);
  }

  if (filter.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filter.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

export function getProduct(id: number): ServiceResult<ProductDetail> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { ok: false, error: "Product not found", statusCode: 404 };
  }

  const isLowStock = product.stock < 10;
  const inventoryValue = Math.round(product.price * product.stock * 100) / 100;

  return {
    ok: true,
    data: {
      ...product,
      isLowStock,
      inventoryValue,
    },
  };
}

export function adjustStock(
  id: number,
  adjustment: number
): ServiceResult<ProductDetail> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { ok: false, error: "Product not found", statusCode: 404 };
  }

  if (typeof adjustment !== "number") {
    return { ok: false, error: "adjustment must be a number", statusCode: 400 };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return { ok: false, error: "Insufficient stock", statusCode: 400 };
  }

  product.stock = newStock;

  return {
    ok: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}

